import { d3_event } from '../../../core/d3-constants';
import { getMousePosition } from '../../../events/eventActions';

export function SizeSliderListener(_, i, ele, eventType) {
    let manager = this,
        event = d3_event(),
        mouse = getMousePosition(manager.tracker.node(), event);

    let data = manager.getData(eventType, mouse);

    manager.associateBehaviours(eventType, data, mouse, event);
}
